using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI N=1e4+5;
int n,m,p,q,f[N],g[N];
il int ff(int x)
{
    return f[x]==x?x:f[x]=ff(f[x]);
}
il int gg(int x)
{
    return g[x]==x?x:g[x]=gg(g[x]);
}
signed main(void)
{
    n=read();m=read();p=read();q=read();
    FOR(i,1,n)f[i]=i;
    FOR(i,1,m)g[i]=i;
    FOR(i,1,p)
    {
        int u=read(),v=read();
        f[ff(u)]=ff(v);
    }
    FOR(i,1,q)
    {
        int u=read(),v=read();
        u=-u;v=-v;
        g[gg(u)]=gg(v);
    }
    int a=ff(1),b=gg(1),c=0,d=0;
    FOR(i,1,n)if(ff(i)==a)c++;
    FOR(i,1,m)if(gg(i)==b)d++;
    writeln(min(c,d));
    return false;
}
